INSERT INTO adt_submissions (id, challenge_id, user_id, participant_name, team_name, repo_url, documentation_url, video_pitch_url, description, claimed_technologies, country, city, status, created_at) VALUES
('a1000001-0000-0000-0000-000000000001', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_1', 'Adaeze Okonkwo', 'SolarGrid AI', 'https://github.com/solargrid-ai/edge-optimizer', 'https://solargrid-ai.notion.site/docs', 'https://www.loom.com/share/solargrid-ai-pitch-2025', 'An edge ML system that optimizes electricity distribution across solar mini-grids in real time. The model runs on a Raspberry Pi 4 and uses load forecasting, battery state-of-charge prediction, and demand-response signals to reduce diesel generator dependency by up to 30%. Trained on 14 months of real metering data from 3 mini-grid sites in Ogun State.', ARRAY['TensorFlow Lite','Raspberry Pi','MQTT','Python','InfluxDB','Grafana']::text[], 'Nigeria', 'Lagos', 'evaluated', '2025-03-10T14:22:00Z'),
('a1000001-0000-0000-0000-000000000002', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_2', 'Youssef Benali', 'CureBionics', 'https://github.com/curebionics/emg-prosthetic', 'https://curebionics.gitbook.io/docs', 'https://www.loom.com/share/curebionics-pitch-2025', 'A low-cost below-elbow bionic prosthetic that uses surface EMG sensors to detect muscle activation patterns and translate them into grip commands. The housing is 3D-printed from recycled PETG, and the control board runs on an STM32 microcontroller drawing under 200mA. Total bill of materials is $85, compared to $3,000+ for imported alternatives. Tested with 6 patients at CHU Ibn Rochd hospital.', ARRAY['STM32','EMG Signal Processing','3D Printing','C/C++','FreeRTOS','Fusion 360']::text[], 'Morocco', 'Casablanca', 'evaluated', '2025-03-08T11:45:00Z'),
('a1000001-0000-0000-0000-000000000003', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_3', 'Njeri Wambui', 'AquaSense', 'https://github.com/aquasense-iot/lorawan-monitor', NULL, 'https://www.loom.com/share/aquasense-pitch-2025', 'An IoT water quality monitoring network using LoRaWAN sensors deployed across community boreholes in Kiambu County. Each node measures pH, turbidity, dissolved oxygen, and temperature, transmitting readings every 15 minutes to a central dashboard. Anomaly detection runs on a lightweight gradient-boosted model that triggers SMS alerts to county water officers when contamination thresholds are breached.', ARRAY['LoRaWAN','The Things Network','ESP32','scikit-learn','Node.js','Twilio']::text[], 'Kenya', 'Nairobi', 'evaluated', '2025-03-12T08:30:00Z'),
('a1000001-0000-0000-0000-000000000004', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_4', 'Kwame Mensah', 'FarmSpeak', 'https://github.com/farmspeak/crop-scanner', NULL, NULL, 'An offline crop disease detection app that runs entirely on a smartphone camera without internet connectivity. The MobileNetV2 model was fine-tuned on 12,000 images of maize, cassava, and cocoa diseases common in West Africa. Inference takes under 2 seconds on mid-range Android phones. Includes voice-based results in Twi and Ewe for farmers who are not literate.', ARRAY['TensorFlow Lite','Android','Kotlin','MobileNetV2','MediaPipe']::text[], 'Ghana', 'Accra', 'evaluated', '2025-03-14T16:10:00Z'),
('a1000001-0000-0000-0000-000000000005', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_5', 'Emeka Okafor', 'ShieldDrone', 'https://github.com/shielddrone/uav-surveillance', 'https://shielddrone.readthedocs.io', 'https://www.loom.com/share/shielddrone-pitch-2025', 'An autonomous border surveillance UAV system that uses onboard computer vision to detect and classify unauthorized crossings in real time. The perception stack runs on an NVIDIA Jetson Orin Nano and fuses RGB, thermal, and LiDAR data. The system operates autonomously for 45-minute missions with automatic return-to-base and can cover a 12km patrol corridor. Designed for use by national security agencies in terrain where ground patrols are impractical.', ARRAY['ROS 2','NVIDIA Jetson','YOLOv8','LiDAR','PX4','C++','Python']::text[], 'Nigeria', 'Abuja', 'evaluated', '2025-03-09T09:15:00Z'),
('a1000001-0000-0000-0000-000000000006', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_6', 'Selamawit Gebru', 'MediScan', NULL, NULL, 'https://www.loom.com/share/mediscan-pitch-2025', 'A portable sickle-cell screening device that uses a smartphone microscope attachment and a trained convolutional neural network to identify sickle-shaped red blood cells in peripheral blood smears. The device costs under $15 to manufacture and the app runs offline on Android 8+. Preliminary testing at Tikur Anbessa Hospital showed 89% sensitivity and 93% specificity compared to gold-standard hemoglobin electrophoresis.', ARRAY['PyTorch Mobile','Android','OpenCV','3D Printing','Java']::text[], 'Ethiopia', 'Addis Ababa', 'evaluated', '2025-03-11T13:00:00Z'),
('a1000001-0000-0000-0000-000000000007', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_7', 'Jean-Pierre Habimana', 'CryptoVault', 'https://github.com/cryptovault-rw/zk-identity', NULL, NULL, 'A zero-knowledge proof identity verification system for mobile banking in East Africa. Uses zk-SNARKs to allow users to prove their identity to financial institutions without revealing underlying personal data. Built on a Circom circuit that generates proofs on-device in under 10 seconds on modern smartphones.', ARRAY['Circom','SnarkJS','React Native','Node.js','Solidity']::text[], 'Rwanda', 'Kigali', 'evaluated', '2025-03-15T10:20:00Z'),
('a1000001-0000-0000-0000-000000000008', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_8', 'Fatima El-Amin', 'ClimateNet', 'https://github.com/climatenet-eg/sat-predict', NULL, NULL, 'A satellite-based climate prediction model that downscales ERA5 reanalysis data to 1km resolution for North Africa using a conditional diffusion model. The system ingests Sentinel-2 imagery and MODIS land surface temperature to produce 7-day precipitation and temperature forecasts tailored to Egyptian agricultural zones.', ARRAY['Python','xarray','PyTorch','Diffusion Models','Google Earth Engine','dask']::text[], 'Egypt', 'Cairo', 'pending', '2025-03-18T07:45:00Z'),
('a1000001-0000-0000-0000-000000000009', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_9', 'Zanele Dlamini', 'NeuroBridge', NULL, NULL, NULL, 'A brain-computer interface system for paralysis rehabilitation that uses low-cost EEG headsets to detect motor imagery patterns and drive a gamified physical therapy protocol. The system adapts difficulty in real time based on patient engagement and neural signal quality, making neuroplasticity-driven rehab accessible outside specialist hospitals.', ARRAY['Python','OpenBCI','scikit-learn','Unity','C#','WebSocket']::text[], 'South Africa', 'Cape Town', 'pending', '2025-03-19T15:30:00Z'),
('a1000001-0000-0000-0000-000000000010', 'c0000001-0000-0000-0000-000000000001', 'usr_participant_10', 'Amina Juma', 'PowerHarvest', 'https://github.com/powerharvest-tz/piezo-energy', NULL, 'https://www.loom.com/share/powerharvest-pitch-2025', 'A piezoelectric energy harvesting system that generates electricity from pedestrian foot traffic in high-density areas such as bus terminals and markets. Each tile module produces 5-8W under sustained traffic and stores energy in supercapacitors for charging mobile phones and powering LED lighting. The system was tested at Kariakoo Market with over 2,000 daily footfalls recorded.', ARRAY['Arduino','Piezoelectric Ceramics','PCB Design','C','React','Firebase']::text[], 'Tanzania', 'Dar es Salaam', 'evaluating', '2025-03-16T12:00:00Z');